  backticks, no explanation. Start your response with { and end with }.

  RULES — follow exactly:
  1. Use WORK EXPERIENCE entries as the primary source of truth. Ignore the Objective section entirely.
  2. "Scale Virtually Certified Virtual Assistant" is a training program, NOT a certification or title. Do not mention it anywhere in the 
  output.
  3. years_of_experience: subtract the year of the EARLIEST work experience entry from 2026. Round to the nearest whole number.
  4. title: a concise, accurate professional title derived from the actual job roles held (e.g. "Property Management & Operations VA", 
  "Executive Virtual Assistant", "Content Operations Specialist", "Real Estate Transaction Coordinator"). Never use "Certified VA" unless 
  a real third-party certification is explicitly listed.
  5. summary: 2-3 sentences written from work history only. Mention specific industries, core responsibilities, and total years. Do not 
  use "certified virtual assistant." Do not copy the Objective section.
  6. industries: list every distinct industry sector found in work history. Be specific (e.g. "Government administration", "Property 
  management", "BPO / Customer service", "Real estate valuation", "Insurance"). Do not merge or omit any.
  7. certifications: include ONLY real named certifications (e.g. "Avaya Certification"). Leave the array empty if none exist.
  8. skills: use precise labels that match what the candidate actually did. Examples — use "Project Coordination" not "Project Management"
  unless they owned full project delivery; use "Basic Website Management" not "Website Building" unless they built sites from scratch; 
  use "Executive Support" not "Operations Management" if the role was EA-level.
  9. skill categories must be one of: Admin & ops | Communication | Content writing | Research | Customer support | Compliance | Sales | 
  Government & public sector
  10. tool categories must be one of: Project management | CRM | Design | Communication | Accounting | AI tools | Data & reporting

  Use exactly this schema:
  {
    "years_of_experience": <integer>,
    "title": "<concise professional title>",
    "english_proficiency": "Native | Fluent | Intermediate | Basic | Unknown",
    "summary": "<2-3 sentence professional summary based on work history>",
    "industries": ["<industry 1>", "<industry 2>"],
    "certifications": ["<certification name>"],
    "skills": [
      { "name": "<skill name>", "category": "<see rule 9>", "proficiency": "<Beginner | Intermediate | Advanced | Expert>" }
    ],
    "tools": [
      { "name": "<tool name>", "category": "<see rule 10>", "proficiency": "<Beginner | Intermediate | Advanced | Expert>" }
    ]
  }` }
      ]
    }]
  };
  return [{ json: { vaId: $('Split VAs - one at a time').item.json.id, claudeBody: JSON.stringify(body) } }];

let raw = $json.content[0].text.trim();
if (raw.startsWith('```')) {
  raw = raw.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
}
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error('Claude returned invalid JSON: ' + raw.substring(0, 200));
}
const vaId = $('Split VAs - one at a time').item.json.id;
return [{ json: { vaId, years_of_experience: parsed.years_of_experience ?? null, english_proficiency: parsed.english_proficiency ?? 'Unknown', summary: parsed.summary ?? '', skills: parsed.skills ?? [], tools: parsed.tools ?? [] } }];

const data = $input.item.json;
const skills = data.skills || [];
if (skills.length === 0) return [{ json: { _skip: true, vaId: data.vaId } }];
return skills.map(s => ({
  json: { vaId: data.vaId, name: s.name, category: s.category, proficiency: s.proficiency }
}));

const categoryItems = $input.all();
const skillItems = $('Code - Build Skill Category Upsert').all();

return categoryItems.map((categoryItem, index) => {
  const skill = skillItems[index]?.json;
  const categoryRecord = categoryItem.json.records?.[0];

  if (!skill) {
    throw new Error(`No matching skill item found for index ${index}`);
  }

  if (!categoryRecord?.id) {
    throw new Error(`No category record ID found for index ${index}`);
  }

  return {
    json: {
      ...skill,
      categoryRecordId: categoryRecord.id,
      requestBody: JSON.stringify({
        performUpsert: {
          fieldsToMergeOn: ["Skill Name"],
        },
        records: [
          {
            fields: {
              "Skill Name": skill.name,
              "Skill Category": [categoryRecord.id],
            },
          },
        ],
      }),
    },
    pairedItem: {
      item: index,
    },
  };
});

const skillUpsertResponses = $input.all();
const originalSkillItems = $('Code - Build Skill Upsert').all();

return skillUpsertResponses.map((skillResponseItem, index) => {
  const original = originalSkillItems[index]?.json;
  const record = skillResponseItem.json.records?.[0];

  if (!original) {
    throw new Error(`No matching original skill item found for index ${index}`);
  }

  if (!record?.id) {
    throw new Error(`No skill record ID found for index ${index}`);
  }

  return {
    json: {
      vaId: original.vaId,
      skillName: original.name,
      skillRecordId: record.id,
      proficiency: original.proficiency,
      requestBody: JSON.stringify({
        records: [
          {
            fields: {
              VA: [original.vaId],
              Skill: [record.id],
              Proficiency: original.proficiency,
            },
          },
        ],
      }),
    },
    pairedItem: {
      item: index,
    },
  };
});

